import os
import subprocess
from google.cloud import storage

def image_convert(event, context):
    bucket_name = event['bucket']
    file_name = event['name']
    conversion_options = event.get('attributes', {}).get('conversion_options', '')

    # Define the input and output paths
    input_blob = f"gs://{bucket_name}/{file_name}"
    output_file_name = f"converted_{file_name}"
    output_blob = f"gs://{bucket_name}/{output_file_name}"

    # Download the image to local temporary storage
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    temp_input_file = f"/tmp/{file_name}"
    blob.download_to_filename(temp_input_file)

    # Prepare the convert command
    convert_command = ['convert', temp_input_file] + conversion_options.split() + [output_file_name]

    # Run the convert command
    subprocess.call(convert_command)

    # Upload the converted image back to Cloud Storage
    converted_blob = bucket.blob(output_file_name)
    converted_blob.upload_from_filename(output_file_name)

    # Clean up temporary files
    os.remove(temp_input_file)
    os.remove(output_file_name)